#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <functional>

void solution_main(); // Forward declaration of the user's main logic

std::string run_with_redirected_io(const std::string& input_str, std::function<void()> program_main) {
    std::stringstream ss_input(input_str);
    std::stringstream ss_output;

    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    program_main();

    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    return ss_output.str();
}

int main() {
    std::string input = "1 2 3\n4 5 6\n";
    std::string expected_output = "Original Matrix:\n1 2 3\n4 5 6\n\nTransposed Matrix:\n1 4\n2 5\n3 6\n";
    std::string actual_output = run_with_redirected_io(input, solution_main);
    std::cout << "Driver output:\n";
    std::cout << "Test Input:\n" << input;
    std::cout << "Expected Output:\n" << expected_output;
    std::cout << "Actual Output:\n" << actual_output;
    return 0;
}
